"use client";

/**
 * QuickActions Component
 *
 * A FAB or floating action bar for quick access to common actions.
 * Optimized for Product Mode with efficient action access.
 *
 * @example
 * ```tsx
 * <QuickActions
 *   variant="fab"
 *   actions={[
 *     { id: 'new', label: 'New Item', icon: <Plus />, onClick: handleNew }
 *   ]}
 * />
 * ```
 */

import { forwardRef, useState, useEffect, useRef } from "react";
import { Plus, X } from "lucide-react";
import type { QuickActionsProps, QuickAction } from "./QuickActions.types";
import styles from "./QuickActions.module.css";

export const QuickActions = forwardRef<HTMLDivElement, QuickActionsProps>(
  (
    {
      actions,
      variant = "fab",
      position = "bottom-right",
      primaryAction,
      triggerIcon,
      showLabels,
      fixed = true,
      offset = 24,
      className,
      style,
      ...rest
    },
    ref,
  ) => {
    const [isOpen, setIsOpen] = useState(false);
    const containerRef = useRef<HTMLDivElement>(null);

    // Determine if labels should show
    const shouldShowLabels = showLabels ?? variant === "bar";

    // Close on outside click
    useEffect(() => {
      if (!isOpen) return;

      const handleClickOutside = (e: MouseEvent) => {
        if (
          containerRef.current &&
          !containerRef.current.contains(e.target as Node)
        ) {
          setIsOpen(false);
        }
      };

      document.addEventListener("mousedown", handleClickOutside);
      return () =>
        document.removeEventListener("mousedown", handleClickOutside);
    }, [isOpen]);

    // Close on Escape
    useEffect(() => {
      if (!isOpen) return;

      const handleKeyDown = (e: KeyboardEvent) => {
        if (e.key === "Escape") {
          setIsOpen(false);
        }
      };

      document.addEventListener("keydown", handleKeyDown);
      return () => document.removeEventListener("keydown", handleKeyDown);
    }, [isOpen]);

    const handleActionClick = (action: QuickAction) => {
      if (!action.disabled) {
        action.onClick();
        if (variant === "fab" || variant === "menu") {
          setIsOpen(false);
        }
      }
    };

    const classNames = [
      styles.quickActions,
      styles[`variant-${variant}`],
      styles[`position-${position}`],
      fixed && styles.fixed,
      isOpen && styles.open,
      className,
    ]
      .filter(Boolean)
      .join(" ");

    const containerStyle = {
      ...style,
      "--offset": `${offset}px`,
    } as React.CSSProperties;

    // FAB variant
    if (variant === "fab") {
      return (
        <div
          ref={containerRef}
          className={classNames}
          style={containerStyle}
          {...rest}
        >
          {/* Action items (shown when expanded) */}
          <div className={styles.fabActions}>
            {actions.map((action, index) => (
              <button
                key={action.id}
                type="button"
                className={`${styles.fabAction} ${action.variant ? styles[`action-${action.variant}`] : ""} ${action.disabled ? styles.actionDisabled : ""}`}
                onClick={() => handleActionClick(action)}
                disabled={action.disabled}
                style={{ transitionDelay: isOpen ? `${index * 50}ms` : "0ms" }}
                title={action.label}
              >
                <span className={styles.fabActionIcon}>{action.icon}</span>
                {shouldShowLabels && (
                  <span className={styles.fabActionLabel}>{action.label}</span>
                )}
              </button>
            ))}
          </div>

          {/* Main FAB trigger */}
          <button
            type="button"
            className={styles.fabTrigger}
            onClick={() => {
              if (primaryAction && !isOpen) {
                handleActionClick(primaryAction);
              } else {
                setIsOpen(!isOpen);
              }
            }}
            aria-expanded={isOpen}
            aria-label={isOpen ? "Close actions" : "Open actions"}
          >
            <span
              className={`${styles.fabTriggerIcon} ${isOpen ? styles.fabTriggerIconRotate : ""}`}
            >
              {isOpen ? <X size={24} /> : triggerIcon || <Plus size={24} />}
            </span>
          </button>
        </div>
      );
    }

    // Bar variant
    if (variant === "bar") {
      return (
        <div ref={ref} className={classNames} style={containerStyle} {...rest}>
          <div className={styles.bar}>
            {actions.map((action) => (
              <button
                key={action.id}
                type="button"
                className={`${styles.barAction} ${action.variant ? styles[`action-${action.variant}`] : ""} ${action.disabled ? styles.actionDisabled : ""}`}
                onClick={() => handleActionClick(action)}
                disabled={action.disabled}
                title={action.label}
              >
                <span className={styles.barActionIcon}>{action.icon}</span>
                {shouldShowLabels && (
                  <span className={styles.barActionLabel}>{action.label}</span>
                )}
                {action.shortcut && (
                  <kbd className={styles.shortcut}>{action.shortcut}</kbd>
                )}
              </button>
            ))}
          </div>
        </div>
      );
    }

    // Menu variant
    return (
      <div
        ref={containerRef}
        className={classNames}
        style={containerStyle}
        {...rest}
      >
        {/* Menu items */}
        {isOpen && (
          <div className={styles.menu}>
            {actions.map((action) => (
              <button
                key={action.id}
                type="button"
                className={`${styles.menuAction} ${action.variant ? styles[`action-${action.variant}`] : ""} ${action.disabled ? styles.actionDisabled : ""}`}
                onClick={() => handleActionClick(action)}
                disabled={action.disabled}
              >
                <span className={styles.menuActionIcon}>{action.icon}</span>
                <span className={styles.menuActionLabel}>{action.label}</span>
                {action.shortcut && (
                  <kbd className={styles.shortcut}>{action.shortcut}</kbd>
                )}
              </button>
            ))}
          </div>
        )}

        {/* Menu trigger */}
        <button
          type="button"
          className={styles.menuTrigger}
          onClick={() => setIsOpen(!isOpen)}
          aria-expanded={isOpen}
          aria-label={isOpen ? "Close menu" : "Open menu"}
        >
          {isOpen ? <X size={20} /> : triggerIcon || <Plus size={20} />}
        </button>
      </div>
    );
  },
);

QuickActions.displayName = "QuickActions";

/**
 * QuickActions Component Types
 *
 * Type definitions for the Orion QuickActions section component.
 * A FAB or floating action bar for quick access to common actions.
 */

import type { HTMLAttributes, ReactNode } from "react";

/**
 * Quick action item
 */
export interface QuickAction {
  /**
   * Unique identifier
   */
  id: string;

  /**
   * Action label
   */
  label: string;

  /**
   * Action icon
   */
  icon: ReactNode;

  /**
   * Click handler
   */
  onClick: () => void;

  /**
   * Keyboard shortcut display
   */
  shortcut?: string;

  /**
   * Disabled state
   */
  disabled?: boolean;

  /**
   * Variant for styling
   */
  variant?: "default" | "primary" | "danger";
}

/**
 * QuickActions position
 */
export type QuickActionsPosition =
  | "bottom-right"
  | "bottom-left"
  | "bottom-center"
  | "top-right"
  | "top-left";

/**
 * QuickActions variant
 */
export type QuickActionsVariant = "fab" | "bar" | "menu";

/**
 * QuickActions section props
 *
 * @example
 * ```tsx
 * // FAB variant (single expandable button)
 * <QuickActions
 *   variant="fab"
 *   actions={[
 *     { id: 'new', label: 'New Item', icon: <Plus />, onClick: () => {} },
 *     { id: 'upload', label: 'Upload', icon: <Upload />, onClick: () => {} }
 *   ]}
 * />
 *
 * // Bar variant (horizontal action bar)
 * <QuickActions
 *   variant="bar"
 *   actions={[...]}
 * />
 * ```
 */
export interface QuickActionsProps extends HTMLAttributes<HTMLDivElement> {
  /**
   * Array of quick actions
   */
  actions: QuickAction[];

  /**
   * Display variant
   * - fab: Floating action button that expands
   * - bar: Horizontal action bar
   * - menu: Vertical menu style
   * @default 'fab'
   */
  variant?: QuickActionsVariant;

  /**
   * Position on screen
   * @default 'bottom-right'
   */
  position?: QuickActionsPosition;

  /**
   * Primary action (shown when FAB is collapsed)
   */
  primaryAction?: QuickAction;

  /**
   * Custom trigger icon for FAB
   */
  triggerIcon?: ReactNode;

  /**
   * Always show labels (bar variant)
   * @default true for bar, false for fab
   */
  showLabels?: boolean;

  /**
   * Fixed position
   * @default true
   */
  fixed?: boolean;

  /**
   * Offset from edge in pixels
   * @default 24
   */
  offset?: number;
}

/**
 * QuickActions Component Styles
 *
 * Optimized for Product Mode (SaaS dashboards).
 * Floating action button and bar variants.
 */

.quickActions {
  z-index: var(--z-sticky);
}

.fixed {
  position: fixed;
}

/* Position variants */
.position-bottom-right {
  bottom: var(--offset);
  right: var(--offset);
}

.position-bottom-left {
  bottom: var(--offset);
  left: var(--offset);
}

.position-bottom-center {
  bottom: var(--offset);
  left: 50%;
  transform: translateX(-50%);
}

.position-top-right {
  top: var(--offset);
  right: var(--offset);
}

.position-top-left {
  top: var(--offset);
  left: var(--offset);
}

/* ============================================================================
 * FAB VARIANT
 * ============================================================================ */

.variant-fab {
  display: flex;
  flex-direction: column-reverse;
  align-items: center;
  gap: var(--spacing-3);
}

.fabTrigger {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 56px;
  height: 56px;
  background: var(--interactive-primary);
  color: var(--interactive-primary-text);
  border: none;
  border-radius: var(--radius-full);
  cursor: pointer;
  box-shadow: var(--shadow-lg);
  transition:
    background-color var(--mode-hover-duration),
    transform var(--mode-hover-duration),
    box-shadow var(--mode-hover-duration);
}

.fabTrigger:hover {
  background: var(--interactive-primary-hover);
  transform: scale(1.05);
}

.fabTrigger:active {
  transform: scale(0.98);
}

.fabTriggerIcon {
  display: flex;
  align-items: center;
  justify-content: center;
  transition: transform var(--transition-normal);
}

.fabTriggerIconRotate {
  transform: rotate(45deg);
}

.fabActions {
  display: flex;
  flex-direction: column-reverse;
  align-items: center;
  gap: var(--spacing-2);
  opacity: 0;
  visibility: hidden;
  transform: translateY(8px);
  transition: all var(--transition-normal);
}

.open .fabActions {
  opacity: 1;
  visibility: visible;
  transform: translateY(0);
}

.fabAction {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
  padding: var(--spacing-2-5) var(--spacing-4);
  background: var(--surface-base);
  color: var(--text-primary);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius-full);
  cursor: pointer;
  box-shadow: var(--shadow-md);
  white-space: nowrap;
  transition: all var(--mode-hover-duration);
  opacity: 0;
  transform: scale(0.8);
}

.open .fabAction {
  opacity: 1;
  transform: scale(1);
}

.fabAction:hover {
  background: var(--surface-subtle);
  border-color: var(--border-moderate);
}

.fabActionIcon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  height: 20px;
}

.fabActionLabel {
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  font-weight: var(--font-weight-medium);
}

/* ============================================================================
 * BAR VARIANT
 * ============================================================================ */

.variant-bar .bar {
  display: flex;
  align-items: center;
  gap: var(--spacing-1);
  padding: var(--spacing-2);
  background: var(--surface-base);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius-container);
  box-shadow: var(--shadow-lg);
}

.barAction {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
  padding: var(--spacing-2) var(--spacing-3);
  background: none;
  color: var(--text-secondary);
  border: none;
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: all var(--mode-hover-duration);
}

.barAction:hover {
  background: var(--surface-subtle);
  color: var(--text-primary);
}

.barActionIcon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 18px;
  height: 18px;
}

.barActionLabel {
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  font-weight: var(--font-weight-medium);
}

/* ============================================================================
 * MENU VARIANT
 * ============================================================================ */

.variant-menu {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: var(--spacing-2);
}

.menuTrigger {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 44px;
  height: 44px;
  background: var(--interactive-primary);
  color: var(--interactive-primary-text);
  border: none;
  border-radius: var(--radius-full);
  cursor: pointer;
  box-shadow: var(--shadow-lg);
  transition: background-color var(--mode-hover-duration);
}

.menuTrigger:hover {
  background: var(--interactive-primary-hover);
}

.menu {
  display: flex;
  flex-direction: column;
  min-width: 180px;
  background: var(--surface-base);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius-control);
  box-shadow: var(--shadow-lg);
  padding: var(--spacing-1);
  animation: menuSlide 150ms ease-out;
}

@keyframes menuSlide {
  from {
    opacity: 0;
    transform: translateY(8px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.menuAction {
  display: flex;
  align-items: center;
  gap: var(--spacing-3);
  width: 100%;
  padding: var(--spacing-2-5) var(--spacing-3);
  background: none;
  color: var(--text-primary);
  border: none;
  border-radius: var(--radius-sm);
  cursor: pointer;
  text-align: left;
  transition: background-color var(--mode-hover-duration);
}

.menuAction:hover {
  background: var(--surface-subtle);
}

.menuActionIcon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 18px;
  height: 18px;
  color: var(--text-secondary);
}

.menuActionLabel {
  flex: 1;
  font-family: var(--font-secondary);
  font-size: var(--font-size-14);
  font-weight: var(--font-weight-medium);
}

/* ============================================================================
 * ACTION VARIANTS
 * ============================================================================ */

.action-primary {
  color: var(--interactive-primary);
}

.action-danger {
  color: var(--text-error);
}

.action-danger:hover {
  background: var(--status-error-bg);
}

.actionDisabled {
  opacity: 0.5;
  cursor: not-allowed;
  pointer-events: none;
}

/* ============================================================================
 * SHORTCUT
 * ============================================================================ */

.shortcut {
  font-family: var(--font-mono);
  font-size: var(--font-size-11);
  color: var(--text-tertiary);
  background: var(--surface-subtle);
  padding: var(--spacing-0-5) var(--spacing-1);
  border-radius: var(--radius-sm);
  margin-left: auto;
}

/* ============================================================================
 * RESPONSIVE
 * ============================================================================ */

@media (max-width: 640px) {
  .fabTrigger {
    width: 48px;
    height: 48px;
  }

  .menuTrigger {
    width: 40px;
    height: 40px;
  }

  .fabActionLabel {
    display: none;
  }

  .fabAction {
    padding: var(--spacing-2-5);
    border-radius: var(--radius-full);
  }
}

export { QuickActions } from "./QuickActions";
export type {
  QuickActionsProps,
  QuickAction,
  QuickActionsVariant,
  QuickActionsPosition,
} from "./QuickActions.types";
